370→  function upsertToolDetailPreview(
371→    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
372→    inputText: string,
373→    event: ChatEvent,
374→    sourceState: SourceScopedState,
375→    source: StreamSource,
376→  ): void {
377→    sourceState.currentAssistantId = undefined;
378→    sourceState.detailBuffers[toolName] = (sourceState.detailBuffers[toolName] || '') + (inputText || '');
379→    const parsed = parseStructuredInput(sourceState.detailBuffers[toolName] || '');
380→    if (!parsed) return;
381→
382→    const detail = buildToolDetailFromArgs(toolName, parsed, 'streaming');
383→    if (!detail) return;
384→
385→    const existingId = sourceState.detailMessageIds[toolName];
386→    const timestamp = resolveEventTimestamp(event);
387→    if (existingId) {
388→      updateById(existingId, msg => ({
389→        ...msg,
390→        event: EVENT_TOOL_INPUT,
391→        content: detail.summary,
392→        timestamp,
393→        toolName,
394→        node: event.node,
395→        toolDetail: detail,
396→        ...getSubagentFields(source),
397→        source,
398→      }));
399→      return;
400→    }
401→
402→    const messageId = generateId();
403→    sourceState.detailMessageIds[toolName] = messageId;
404→    push({
405→      id: messageId,
406→      role: 'assistant',
407→      content: detail.summary,
408→      timestamp,
409→      event: EVENT_TOOL_INPUT,
410→      toolName,
411→      node: event.node,
412→      toolDetail: detail,
413→      ...getSubagentFields(source),
414→      source,
415→    });
416→  }
