619→  function handleAssistantEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
620→    const content = getEventContent(event);
621→    const thinking = ((event.data as Record<string, unknown>)?.thinking as string) || '';
622→    appendAssistantChunk(event, sourceState, source, { content, thinking });
623→  }
