625→  function handleThinkingEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
626→    const data = event.data as Record<string, unknown>;
627→    const thinkingText = ((data?.thinking as string) || '') + ((data?.content as string) || '');
628→    appendAssistantChunk(event, sourceState, source, { thinking: thinkingText });
629→  }
