631→  function handleToolInputEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
632→    const { toolName, inputText } = getToolInputData(event);
633→
634→    if (toolName === TOOL_RENDER_UI) {
635→      sourceState.currentAssistantId = undefined;
636→      sourceState.generativeUIPreviewBuffer += inputText || '';
637→      const payload = parseGenerativeUIPreview(sourceState.generativeUIPreviewBuffer);
638→      if (payload) upsertGenerativeUIPreview(payload, event, sourceState, source);
639→      return;
640→    }
641→
642→    if (toolName === TOOL_WRITE_TODOS) {
643→      sourceState.todoBuffer += inputText || '';
644→      const todos = parseTodoItems(sourceState.todoBuffer);
645→      if (todos.length > 0) upsertTodo(todos, event, sourceState, source);
646→      return;
647→    }
648→
649→    if (isDetailToolName(toolName)) {
650→      upsertToolDetailPreview(toolName, inputText, event, sourceState, source);
651→      return;
652→    }
653→
654→    if (!inputText) {
655→      return;
656→    }
657→
658→    const last = state.messages[state.messages.length - 1];
659→    if (
660→      last?.event === EVENT_TOOL_INPUT &&
661→      last.toolName === toolName &&
662→      isSameSource(last.source, source)
663→    ) {
664→      updateById(last.id, msg => ({ ...msg, content: msg.content + inputText }));
665→      return;
666→    }
667→
668→    pushAssistantMessage(event, source, inputText, {
669→      event: EVENT_TOOL_INPUT,
670→      toolName,
671→    });
672→  }
673→
674→  function handleToolCallEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
675→    const data = event.data as Record<string, unknown>;
676→    const toolName = data?.name as string | undefined;
677→    const toolCallId = getToolCallId(data);
678→
679→    if (toolName === TOOL_WRITE_TODOS) {
680→      const input = typeof data?.input === 'string' ? data.input : JSON.stringify(data?.input ?? {});
681→      const todos = parseTodoItems(input);
682→      finalizeTodo(todos, event, sourceState, source);
683→      return;
684→    }
685→
686→    if (toolName && isDetailToolName(toolName)) {
687→      upsertToolDetailCall(toolName, data, event, sourceState, source);
688→      return;
689→    }
690→
691→    const content = formatEventContent(event);
692→    if (!content) {
693→      return;
694→    }
695→
696→    pushAssistantMessage(event, source, content, {
697→      event: EVENT_TOOL_CALL,
698→      toolName,
699→      toolCallId,
700→    });
701→  }
702→
703→  function handleToolCallResultEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
704→    const data = event.data as Record<string, unknown>;
705→    const toolName = data?.name as string | undefined;
706→    const toolCallId = getToolCallId(data);
707→    if (toolName === TOOL_WRITE_TODOS) return;
708→
709→    if (toolName && isDetailToolName(toolName)) {
710→      finalizeToolDetailResult(toolName, data, event, sourceState, source);
711→      return;
712→    }
713→
714→    const content = formatEventContent(event);
715→    const outputLength = typeof data?.outputLength === 'number' ? data.outputLength as number : undefined;
716→    const isError = !!data?.error;
717→    if (!content) {
718→      return;
719→    }
720→
721→    pushAssistantMessage(event, source, content, {
722→      event: EVENT_TOOL_CALL_RESULT,
723→      toolName,
724→      toolCallId,
725→      outputLength,
726→      isError,
727→    });
728→  }
729→
730→  function handleDeliverEvent(event: ChatEvent, source: StreamSource): void {
731→    const content = formatEventContent(event);
732→    if (!content) {
733→      return;
734→    }
735→
736→    pushAssistantMessage(event, source, content, {
737→      event: EVENT_DELIVER,
738→    });
739→  }
740→
741→  function handleSimpleAssistantEvent(event: ChatEvent, source: StreamSource): void {
742→    const content = formatEventContent(event);
743→    const data = event.data as Record<string, unknown> | undefined;
744→    const toolName =
745→      event.event === EVENT_ERROR
746→        ? ((data?.toolName as string) || (data?.name as string) || undefined)
747→        : ((data?.name as string) || (data?.agentName as string) || event.node);
748→
749→    pushAssistantMessage(event, source, content, {
750→      event: event.event,
751→      toolName,
752→      isError: event.event === EVENT_ERROR ? true : undefined,
753→    });
754→  }
755→
756→  function applyEvent(event: ChatEvent): void {
757→    const { event: type } = event;
758→    const source = resolveEventSource(event);
759→    const sourceState = getSourceState(source);
760→
761→    // subagent 的 agent-end / assistant-end 推空消息用于 UI 标记结束边界；
762→    // main source 的同类事件在下方的 FILTERED_MESSAGE_EVENT_SET 中被过滤掉。
763→    if ((type === EVENT_AGENT_END || type === EVENT_ASSISTANT_END) && source.kind === 'subagent') {
764→      sourceState.currentAssistantId = undefined;
765→      const usage = type === EVENT_ASSISTANT_END ? parseTokenUsageFromAssistantEndData(event.data) : undefined;
766→      pushAssistantMessage(event, source, '', {
767→        event: type,
768→        ...(usage ? { tokenUsage: { inputTokens: usage.inputTokens, outputTokens: usage.outputTokens, totalTokens: usage.totalTokens } } : {}),
769→      });
770→      return;
771→    }
772→
773→    // 生命周期/控制事件由前端显式过滤，不产出消息（仅对 main source 生效）。
774→    if (FILTERED_MESSAGE_EVENT_SET.has(type)) {
775→      sourceState.currentAssistantId = undefined;
776→      return;
777→    }
778→
779→    // ── 用户消息 ─────────────────────────────────────────────────────────────────
780→    if (type === EVENT_USER) {
781→      sourceState.currentAssistantId = undefined;
782→      handleUserEvent(event);
783→      return;
784→    }
785→
786→    // ── todo-update 自定义事件（on_tool_start 触发，携带完整 todos 数组）────────────
787→    if (type === EVENT_TODO_UPDATE) {
788→      sourceState.currentAssistantId = undefined;
789→      handleTodoUpdateEvent(event, sourceState, source);
790→      return;
791→    }
792→
793→    // ── generative-ui 事件（render-ui 工具产出）─────────────────────────────────────
794→    if (type === EVENT_GENERATIVE_UI) {
795→      sourceState.currentAssistantId = undefined;
796→      handleGenerativeUIEvent(event, sourceState, source);
797→      return;
798→    }
799→
800→    // ── set-generative-ui-answer（resume 时回写用户选择）─────────────────────────────
801→    if (type === EVENT_SET_GENERATIVE_UI_ANSWER) {
802→      handleSetGenerativeUIAnswer(event);
803→      return;
804→    }
805→
806→    // ── assistant / thinking ──────────────────────────────────────────────────────
807→    if (type === EVENT_ASSISTANT) {
808→      handleAssistantEvent(event, sourceState, source);
809→      return;
810→    }
811→
812→    if (type === EVENT_THINKING) {
813→      handleThinkingEvent(event, sourceState, source);
814→      return;
815→    }
816→
817→    // 非 assistant 事件重置当前 assistant 追踪
818→    sourceState.currentAssistantId = undefined;
819→
820→    // ── context-summarized ───────────────────────────────────────────────────────
821→    if (type === EVENT_CONTEXT_SUMMARIZED) {
822→      const data = event.data as Record<string, unknown> | undefined;
823→      const message = (data?.message as string) || 'Context 已压缩';
824→      pushAssistantMessage(event, source, message, {
825→        event: EVENT_CONTEXT_SUMMARIZED,
826→      });
827→      return;
828→    }
829→
830→    // ── tool-input ────────────────────────────────────────────────────────────────
831→    if (type === EVENT_TOOL_INPUT) {
832→      handleToolInputEvent(event, sourceState, source);
833→      return;
834→    }
835→
836→    // ── tool-call ─────────────────────────────────────────────────────────────────
837→    if (type === EVENT_TOOL_CALL) {
838→      handleToolCallEvent(event, sourceState, source);
839→      return;
840→    }
841→
842→    // ── tool-call-result ──────────────────────────────────────────────────────────
843→    if (type === EVENT_TOOL_CALL_RESULT) {
844→      handleToolCallResultEvent(event, sourceState, source);
845→      return;
846→    }
847→
848→    // ── deliver ───────────────────────────────────────────────────────────────────
849→    if (type === EVENT_DELIVER) {
850→      handleDeliverEvent(event, source);
851→      return;
852→    }
853→
854→    // ── error / tool-output ───────────────────────────────────────────────────────
855→    if (type === EVENT_ERROR || type === EVENT_TOOL_OUTPUT) {
856→      handleSimpleAssistantEvent(event, source);
857→    }
858→  }
859→
860→  return {
861→    applyEvent,
862→    /** 返回当前消息列表的浅拷贝（供 setMessages 使用） */
863→    getMessages: (): Message[] => [...state.messages],
864→    getTodoTree: (): TodoTreeItem[] => [...state.todoTree],
865→  };
866→}
