'use client';

import {
  Renderer,
  StateProvider,
  ActionProvider,
  VisibilityProvider,
  ValidationProvider,
  useUIStream,
} from '@json-render/react';
import { registry } from '@/lib/generative-ui/registry';

export default function GenerativeUITestPage() {
  const { spec, isStreaming, error, rawLines, send, clear } = useUIStream({
    api: '/api/generative-ui/generate',
  });

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const prompt = formData.get('prompt') as string;
    if (prompt.trim()) send(prompt.trim());
  };

  return (
    <div className="min-h-screen bg-background p-8">
      <div className="mx-auto max-w-3xl">
        <div className="mb-6 flex items-center justify-between">
          <h1 className="text-2xl font-bold">Generative UI — Quick Start Test</h1>
          {spec && (
            <button
              type="button"
              onClick={clear}
              className="rounded border px-3 py-1 text-sm text-muted-foreground hover:bg-muted"
            >
              清除
            </button>
          )}
        </div>

        <StateProvider initialState={{}}>
          <VisibilityProvider>
            <ActionProvider handlers={{}}>
              <ValidationProvider customFunctions={{}}>
                {/* Input form */}
                <form onSubmit={handleSubmit} className="mb-8 flex gap-2">
                  <input
                    name="prompt"
                    placeholder="描述你想要的 UI，例如：生成一个杭州旅行推荐卡片"
                    className="flex-1 rounded border bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary"
                    disabled={isStreaming}
                  />
                  <button
                    type="submit"
                    disabled={isStreaming}
                    className="rounded bg-primary px-4 py-2 text-sm font-medium text-primary-foreground disabled:opacity-50"
                  >
                    {isStreaming ? '生成中…' : '生成'}
                  </button>
                </form>

                {/* Error */}
                {error && (
                  <div className="mb-4 rounded border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
                    {error.message}
                  </div>
                )}

                {/* Renderer — 1:1 Quick Start */}
                <Renderer spec={spec} registry={registry} loading={isStreaming} />

                {/* Debug: raw JSONL patches */}
                {rawLines.length > 0 && (
                  <details className="mt-8 rounded border p-4">
                    <summary className="cursor-pointer text-xs font-medium text-muted-foreground">
                      Raw JSONL patches ({rawLines.length} lines)
                    </summary>
                    <pre className="mt-2 max-h-64 overflow-auto text-xs leading-relaxed text-muted-foreground">
                      {rawLines.join('\n')}
                    </pre>
                  </details>
                )}
              </ValidationProvider>
            </ActionProvider>
          </VisibilityProvider>
        </StateProvider>
      </div>
    </div>
  );
}

