import { tool } from '@langchain/core/tools';
import { interrupt } from '@langchain/langgraph';
import { validateSpec, autoFixSpec } from '@json-render/core';
import { z } from 'zod';
import { EToolName } from '../../common/constant';

interface Spec {
  root: string;
  elements: Record<string, unknown>;
  state?: Record<string, unknown>;
}

function isValidSpecShape(value: unknown): value is Spec {
  return (
    !!value &&
    typeof value === 'object' &&
    typeof (value as Record<string, unknown>).root === 'string' &&
    typeof (value as Record<string, unknown>).elements === 'object'
  );
}

export const renderUITool = tool(
  async (input) => {
    if (!input.title?.trim()) {
      throw new Error('render-ui 缺少 title');
    }
    if (!isValidSpecShape(input.spec)) {
      throw new Error('render-ui 缺少有效的 spec（需包含 root 和 elements）');
    }

    let spec = input.spec as Spec;
    const { valid } = validateSpec(spec as Parameters<typeof validateSpec>[0]);
    if (!valid) {
      spec = autoFixSpec(spec as Parameters<typeof autoFixSpec>[0]) as unknown as Spec;
    }

    if (input.interactive) {
      const answer = interrupt({
        kind: 'generative-ui' as const,
        title: input.title,
        spec,
      });
      return [
        typeof answer === 'string' ? answer : JSON.stringify(answer),
        null,
      ] as const;
    }

    return [
      `已通过 Generative UI 向用户展示「${input.title}」，用户已看到完整的富文本卡片。请勿再以文字或 markdown 重复相同内容，直接继续后续任务或结束回复。`,
      { title: input.title, spec },
    ] as const;
  },
  {
    name: EToolName.RenderUI,
    description:
      '渲染富 UI 组件。可用于展示信息（interactive=false）或收集用户输入（interactive=true）。' +
      '需提供符合 json-render spec 格式（flat-map: root + elements + state）的 UI 定义。' +
      '当 interactive=true 时，调用后暂停执行等待用户回复。',
    responseFormat: 'content_and_artifact',
    schema: z.object({
      title: z.string().describe('UI 卡片标题'),
      spec: z
        .record(z.string(), z.any())
        .describe('json-render spec 对象，flat-map 格式（root + elements + state）'),
      interactive: z
        .boolean()
        .optional()
        .default(false)
        .describe(
          '是否需要等待用户交互。false=纯展示，agent 继续执行；true=暂停等待用户回复',
        ),
    }),
  },
);

