149→function createContentPreview(content: string, headLines = 5, tailLines = 5): string {
150→  const lines = content.split('\n');
151→  if (lines.length <= headLines + tailLines) {
152→    return lines.map((line, i) => `${i + 1}\t${line.substring(0, 1000)}`).join('\n');
153→  }
154→  const head = lines.slice(0, headLines).map((line, i) => `${i + 1}\t${line.substring(0, 1000)}`).join('\n');
155→  const truncation = `\n... [${lines.length - headLines - tailLines} lines truncated] ...\n`;
156→  const tailStart = lines.length - tailLines + 1;
157→  const tail = lines.slice(-tailLines).map((line, i) => `${tailStart + i}\t${line.substring(0, 1000)}`).join('\n');
158→  return head + truncation + tail;
159→}
