import { Body, Controller, Get, Inject, Param, Post, Query, Req, Res, ValidationPipe } from '@nestjs/common';
import { Request, Response } from 'express';
import { ChatService } from './chat.service';
import { ChatDto } from './chat.dto';

@Controller('/api/chat')
export class ChatController {
  @Inject()
  private chatService!: ChatService;

  @Get('/events/:id')
  public async getEvents(@Req() request: Request, @Res() response: Response, @Param('id') id: string) {
    const stream = await this.chatService.getEvents(request, response, id);
    stream?.pipe(response);
  }

  @Get('/session-files/:id')
  public async getSessionFiles(@Param('id') id: string) {
    return this.chatService.getSessionFiles(id);
  }

  @Get('/skills')
  public async getSkills() {
    return this.chatService.getSkills();
  }

  @Get('/session-files/:id/content')
  public async getSessionFileContent(@Param('id') id: string, @Query('path') filePath: string) {
    return this.chatService.getSessionFileContent(id, filePath);
  }

  @Post('/')
  public async chat(
    @Req() request: Request,
    @Res() response: Response,
    @Body(new ValidationPipe({ transform: true, whitelist: true, forbidNonWhitelisted: true })) dto: ChatDto,
  ) {
    const stream = await this.chatService.chat(request, response, dto);
    stream?.pipe(response);
  }
}

