export interface IGenerativeUIPayload {
  kind: 'generative-ui';
  title: string;
  spec: Record<string, unknown>;
  interactive?: boolean;
}

export interface IResumePayload {
  interruptId?: string;
  answer: string | Record<string, unknown>;
}

export function formatGenerativeUIAnswer(answer: unknown): string {
  if (typeof answer === 'string') return answer;

  if (!answer || typeof answer !== 'object' || Array.isArray(answer)) {
    return '用户未提供信息';
  }

  const entries = Object.entries(answer as Record<string, unknown>)
    .map(([key, value]) => `- ${key}: ${formatValue(value)}`)
    .join('\n');

  return entries ? `用户回复：\n\n${entries}` : '用户未提供信息';
}

function formatValue(value: unknown): string {
  if (Array.isArray(value)) {
    return value.map(it => String(it)).join(', ');
  }
  if (value == null || value === '') {
    return '未填写';
  }
  return String(value);
}

