  1→import { BadRequestException, Inject, Injectable, Logger, Scope } from '@nestjs/common';
  2→import { Request, Response } from 'express';
  3→import { PassThrough } from 'stream';
  4→import { randomUUID } from 'crypto';
  5→import { InjectModel } from '@nestjs/mongoose';
  6→import { Model } from 'mongoose';
  7→import { Command } from '@langchain/langgraph';
  8→import { Conversation } from '../conversation/conversation.entity';
  9→import { ConversationService } from '../conversation/conversation.service';
 10→import { EventsService, ILinkedEvent } from '../events/events.service';
 11→import { formatError, getErrorCauseChain, retry } from '../../common/utils';
 12→import { AgentsService, IGraphEvent } from '../../agents/agents.service';
 13→import { TalkableAgents } from '../../common/constant';
 14→import { ChatDto } from './chat.dto';
 15→import { normalizeResumePayload, normalizeSlashSkillMentions } from './chat.payload';
 16→import { ConversationSandboxManager } from '../../agents/sandbox/conversation-sandbox.manager';
 17→import { ConversationTokenUsage } from '../conversation/conversation.entity';
 18→import { normalizeSessionFileContent } from './session-file-content';
 19→import { listLocalSkillNames } from '../../agents/sandbox/providers/initial-files.provider';
 20→import { filterSessionFilesForResponse } from './session-files';
 21→
 22→@Injectable({ scope: Scope.DEFAULT })
 23→export class ChatService {
 24→  @Inject()
 25→  private graph!: AgentsService;
 26→
 27→  @Inject()
 28→  private conversation!: ConversationService;
 29→
 30→  @Inject()
 31→  private events!: EventsService;
 32→
 33→  @Inject()
 34→  private sandboxManager!: ConversationSandboxManager;
 35→
 36→  @InjectModel(Conversation.name)
 37→  private conversationModel!: Model<Conversation>;
 38→
 39→  private readonly logger = new Logger(ChatService.name);
 40→
 41→  private toClientEvent<T extends Record<string, unknown>>(chunk: T) {
 42→    const { id, timestamp, ...rest } = chunk;
 43→    return rest;
 44→  }
 45→
 46→  private extractTokenUsageFromAssistantEnd(chunk: ILinkedEvent): ConversationTokenUsage | undefined {
 47→    if (chunk.event !== 'assistant-end') {
 48→      return undefined;
 49→    }
 50→    const data = chunk.data as Record<string, unknown> | undefined;
 51→    if (!data || typeof data !== 'object') {
 52→      return undefined;
 53→    }
 54→    const usage = data.usage as Record<string, unknown> | undefined;
 55→    if (!usage || typeof usage !== 'object') {
 56→      return undefined;
 57→    }
 58→
 59→    const inputTokens = typeof usage.inputTokens === 'number' ? usage.inputTokens : undefined;
 60→    const outputTokens = typeof usage.outputTokens === 'number' ? usage.outputTokens : undefined;
 61→    const totalTokens = typeof usage.totalTokens === 'number' ? usage.totalTokens : undefined;
 62→    if (
 63→      typeof inputTokens !== 'number' ||
 64→      typeof outputTokens !== 'number' ||
 65→      typeof totalTokens !== 'number'
 66→    ) {
 67→      return undefined;
 68→    }
 69→
 70→    const promptTokens = typeof usage.promptTokens === 'number' ? usage.promptTokens : undefined;
 71→    const completionTokens = typeof usage.completionTokens === 'number' ? usage.completionTokens : undefined;
 72→    const cachedInputTokens = typeof usage.cachedInputTokens === 'number' ? usage.cachedInputTokens : undefined;
 73→    const reasoningOutputTokens = typeof usage.reasoningOutputTokens === 'number' ? usage.reasoningOutputTokens : undefined;
 74→
 75→    return {
 76→      inputTokens,
 77→      outputTokens,
 78→      totalTokens,
 79→      ...(typeof promptTokens === 'number' ? { promptTokens } : {}),
 80→      ...(typeof completionTokens === 'number' ? { completionTokens } : {}),
 81→      ...(typeof cachedInputTokens === 'number' ? { cachedInputTokens } : {}),
 82→      ...(typeof reasoningOutputTokens === 'number' ? { reasoningOutputTokens } : {}),
 83→    };
 84→  }
 85→
 86→  async getSessionFiles(id: string) {
 87→    return filterSessionFilesForResponse(await this.sandboxManager.listFiles(id));
 88→  }
 89→
 90→  async getSkills() {
 91→    return listLocalSkillNames();
 92→  }
 93→
 94→  async getSessionFileContent(id: string, filePath: string) {
 95→    return normalizeSessionFileContent(await this.sandboxManager.readFile(id, filePath));
 96→  }
 97→
 98→
 99→  async getEvents(request: Request, response: Response, id: string) {
100→    const conversation = await this.conversationModel.findOne({ id });
101→    if (!conversation?.head) {
102→      response.status(404);
103→      return;
104→    }
105→
106→    this.enableStream(request, response);
107→    const ac = new AbortController();
108→    const ws = new PassThrough();
109→    const head = conversation.head;
110→    (async () => {
111→      try {
112→        const stream = this.events.getStream(id, head, ac.signal);
113→        for await (const chunk of stream) {
114→          ws.write(JSON.stringify(this.toClientEvent(chunk as unknown as Record<string, unknown>)) + '\n');
115→        }
116→      } catch (error) {
117→        this.logger.error({ conversationId: id, error }, 'Failed to stream chat history');
118→      } finally {
119→        ws.end();
120→      }
121→    })();
122→    request.on('close', ac.abort.bind(ac));
123→    response.status(200);
124→    return ws;
125→  }
126→
127→  async chat(
128→    request: Request,
129→    response: Response,
130→    dto: ChatDto,
131→  ) {
132→    let { model, id, text, attachments } = dto;
133→    const resume = normalizeResumePayload(dto);
134→
135→    this.enableStream(request, response);
136→    const ac = new AbortController();
137→    const ws = new PassThrough();
138→
139→    let conversation: Conversation | null | undefined;
140→    if (!id) {
141→      id = randomUUID();
142→      ws.write(JSON.stringify({ event: 'conversation-create', data: { conversationId: id } }) + '\n');
143→      await this.conversationModel.create({ id, topic: text, modelName: model });
144→    } else {
145→      conversation = await this.conversationModel.findOne({ id });
146→      if (conversation?.modelName) {
147→        model = conversation.modelName;
148→      }
149→      // generating检查
150→      const generating = await this.conversation.isGenerating(id);
151→      if (generating) {
152→        response.status(409);
153→        return;
154→      }
155→    }
156→
157→    if (!model) {
158→      throw new BadRequestException('model 不能为空');
159→    }
160→
161→    const save = await this.createEventsSaver(id);
162→
163→    let query: string | Command | undefined;
164→
165→    // 新问题
166→    if (text) {
167→      const normalizedText = normalizeSlashSkillMentions(text, await this.getSkills());
168→      query = '';
169→      // 附件（如果有）
170→      if (attachments?.length) {
171→        query += '<attachments>\n';
172→        query += attachments.map(it => JSON.stringify(it)).join('\n');
173→        query += '\n</attachments>\n';
174→      }
175→      query += normalizedText;
176→      query = query.trim();
177→      // 保存用户的问题和附件
178→      await save({
179→        id: randomUUID(),
180→        event: 'user',
181→        data: { text, attachments },
182→        timestamp: Date.now(),
183→      });
184→    }
185→
186→    // 信息补充
187→    if (resume) {
188→      const resumeValue = resume.interruptId ? { [resume.interruptId]: resume.answer } : resume.answer;
189→      query = new Command({ resume: resumeValue });
190→      await save({
191→        id: randomUUID(),
192→        event: 'set-generative-ui-answer',
193→        data: resume,
194→        timestamp: Date.now(),
195→      });
196→
197→      if (typeof resume.answer === 'string') {
198→        await save({
199→          id: randomUUID(),
200→          event: 'user',
201→          data: { text: resume.answer, attachments: [] },
202→          timestamp: Date.now(),
203→        });
204→      }
205→    }
206→
207→    if (!query) {
208→      throw new BadRequestException('请求体必须提供 text，或提供合法的 resume / requirements');
209→    }
210→
211→    const generator = this.graph.run(query, {
212→      conversation_id: id,
213→      model,
214→      signal: ac.signal,
215→      request
216→    });
217→    this.pipe(id, generator, ws, ac, save);
218→    response.status(200);
219→    return ws;
220→  }
221→
222→  // 返回对应conversation_id的savor
223→  // savor的作用是，通过队列保存chunk，在chunk id一样时覆写，并且构造链表
224→  // 在conversation中保存head和tail，head为了获取整个链表，tail为了继续写入新的链表节点
225→  private async createEventsSaver(id: string) {
226→    const enqueue = this.createQueuedExecutor();
227→    const conversation = await this.conversationModel.findOne({ id });
228→    // 获取对话的最后一个节点的内容
229→    let buffer: ILinkedEvent | null | undefined = conversation?.tail
230→      ? await this.events.getTail(id, conversation.tail)
231→      : null;
232→
233→    return async (chunk?: ILinkedEvent) => {
234→      // 保存后续传入的内容
235→      if (buffer) {
236→        const diff = chunk?.id !== buffer.id;
237→
238→        if (diff) {
239→          // 指向下一个节点
240→          buffer.next_id = chunk?.id;
241→        }
242→
243→        // 保存引用，用在闭包里，避免后面改写引用导致存入的内容丢失
244→        const snapshot = buffer;
245→        // 串行写入。流式事件可能很密集，直接并发 events.set 可能导致顺序错乱或覆盖。队列保证一次只处理一个任务。
246→        enqueue({
247→          key: buffer.id,
248→          func: retry(() => this.events.set(id, snapshot), { interval: 300 }),
249→        });
250→
251→        if (diff) {
252→          const partial: Partial<Conversation> = { tail: buffer.id };
253→          if (buffer.node && TalkableAgents.includes(buffer.node)) {
254→            partial.node = buffer.node;
255→          }
256→          await this.conversationModel.updateOne({ id }, partial);
257→          buffer = chunk;
258→        }
259→      } else if (chunk) {
260→        buffer = chunk;
261→        // 仅在对话没有 head 时才记录（避免因 Redis 丢失 tail 数据时覆盖已有的历史链）
262→        if (!conversation?.head) {
263→          await this.conversationModel.updateOne({ id }, { head: chunk.id });
264→        }
265→      }
266→    };
267→  }
268→
269→  // 队列写入
270→  private createQueuedExecutor() {
271→    interface IAction {
272→      key: string;
273→      func: () => Promise<void>;
274→    }
275→
276→    const queue: IAction[] = [];
277→    let loading = false;
278→
279→    const dequeue = () => {
280→      loading = true;
281→      const action = queue.shift();
282→      if (action) {
283→        // 递归调用出队，确保每个任务都能被执行
284→        action.func().finally(dequeue);
285→      } else {
286→        loading = false;
287→      }
288→    };
289→
290→    const enqueue = (action: IAction) => {
291→      // 如果队列中有对应的任务，则替换func为新的func
292→      const existed = queue.find(it => it.key === action.key);
293→      if (existed) {
294→        existed.func = action.func;
295→        return;
296→      }
297→      // 如果没有任务，则直接加入队列
298→      queue.push(action);
299→      // 如果不处在loading态（没有进行中的任务，则开始出队）
300→      if (!loading) {
301→        dequeue();
302→      }
303→    };
304→
305→    return enqueue;
306→  }
307→
308→  // 分片聚合，如果是一连串同类型的chunk，则id始终都是这串的第一个chunk的id，但是内容一直拼接。
309→  private createChunkAggregator() {
310→    // 上一个事件
311→    let latest: IGraphEvent | undefined;
312→    const concat = (a: string | undefined | null, b: string | undefined | null) => (a && b ? a + b : a || b);
313→    const getSourceKey = (event?: IGraphEvent) => event?.subagent_namespace || 'main';
314→
315→    return (chunk: IGraphEvent) => {
316→      // 连续 assistant 分片同节点则合并 thinking 与 content ，避免存储碎片过多
317→      if (
318→        chunk.event === 'assistant' &&
319→        latest?.event === 'assistant' &&
320→        chunk.node === latest.node &&
321→        getSourceKey(chunk) === getSourceKey(latest)
322→      ) {
323→        // @ts-expect-error: type todo
324→        latest.data.thinking = concat(latest.data.thinking, chunk.data.thinking);
325→        // @ts-expect-error: type todo
326→        latest.data.content = concat(latest.data.content, chunk.data.content);
327→        return latest;
328→      }
329→
330→      // 连续 tool-input 同工具名则拼接输入文本
331→      if (
332→        chunk.event === 'tool-input' &&
333→        latest?.event === 'tool-input' &&
334→        getSourceKey(chunk) === getSourceKey(latest) &&
335→        // @ts-expect-error: type todo
336→        chunk.data.name === latest.data.name
337→      ) {
338→        // @ts-expect-error: type todo
339→        latest.data.input = latest.data.input + chunk.data.input;
340→        return latest;
341→      }
342→
343→      latest = chunk;
344→      return chunk;
345→    };
346→  }
347→
348→  private async pipe(
349→    id: string,
