import { Module } from '@nestjs/common';
import { ConfigModule } from './config/config.module';
import { MongoModule } from './database/mongo/mongo.module';
import { RedisModule } from './database/redis/redis.module';
import { ChatModule } from './api/chat/chat.module';
import { ConversationModule } from './api/conversation/conversation.module';
import { AttachmentModule } from './api/attachment/attachment.module';
import { AgentsModule } from './agents/agents.module';
import { EventsModule } from './api/events/events.module';
import { GenerativeUIModule } from './api/generative-ui/generative-ui.module';

@Module({
  imports: [
    ConfigModule,
    MongoModule,
    RedisModule,
    ChatModule,
    ConversationModule,
    AttachmentModule,
    AgentsModule,
    EventsModule,
    GenerativeUIModule,
  ],
})
export class AppModule {}

import { defineRegistry } from '@json-render/react';
import { shadcnComponents } from '@json-render/shadcn';
import { catalog } from './catalog';

export const { registry } = defineRegistry(catalog, {
  components: {
    Card: shadcnComponents.Card,
    Stack: shadcnComponents.Stack,
    Grid: shadcnComponents.Grid,
    Separator: shadcnComponents.Separator,
    Tabs: shadcnComponents.Tabs,
    Accordion: shadcnComponents.Accordion,
    Heading: shadcnComponents.Heading,
    Text: shadcnComponents.Text,
    Badge: shadcnComponents.Badge,
    Alert: shadcnComponents.Alert,
    Table: shadcnComponents.Table,
    Button: shadcnComponents.Button,
    Radio: shadcnComponents.Radio,
    Checkbox: shadcnComponents.Checkbox,
    Select: shadcnComponents.Select,
    Input: shadcnComponents.Input,
    Switch: shadcnComponents.Switch,
    ButtonGroup: shadcnComponents.ButtonGroup,
    ToggleGroup: shadcnComponents.ToggleGroup,
  },
  actions: {
    submit: async () => {},
    cancel: async () => {},
  },
});

export const SearchResultMaxLength = 256;

export const SearchErrorMessage = '未查询到相关信息';


export enum ENodeName {
  Coordinator = 'coordinator',
  Planner = 'planner',
  Researcher = 'researcher',
  Writer = 'writer',
}

export const TalkableAgents: ENodeName[] = [
  ENodeName.Coordinator,
  ENodeName.Planner,
  ENodeName.Researcher,
  ENodeName.Writer,
];

export enum EToolName {
  RenderUI = 'render-ui',
  Dispatch = 'dispatch',
  TextToImage = 'text-to-image',
  Execute = 'execute',
  Planning = 'planning',
  Next = 'next',
  Deliver = 'deliver',
  GetGeolocation = 'get-geolocation',
  GetWeather = 'get-weather',
  GetTrainRoute = 'get-train-route',
  SearchPoiByType = 'search-poi-by-type',
  SearchPoiByName = 'search-poi-by-name',
  SearchPoiByLocation = 'search-poi-by-location',
  FileReader = 'file-reader',
  VideoReader = 'video-reader',
  ImageReader = 'image-reader',
  GetCurrentTime = 'get-current-time',
  WriteTodos = 'write_todos',
  WriteFile = 'write_file',
}

// 这些工具都需要在模型流式生成参数时提前透出 tool-input，
// 让前端能在工具真正执行前展示表单或 TODO 预览。
// write_file 会携带大段正文，继续透传会放大 SSE / history / 前端聚合成本，因此移除。
export const ALLOW_TOOL_INPUT: string[] = [
  EToolName.RenderUI,
  EToolName.WriteTodos,
  EToolName.Execute,
  'task',
];

// 这些工具的结果可能包含大段文件正文，只向前端透出首尾摘要，避免消息和历史回放卡顿。
export const SUMMARIZED_TOOL_CALL_RESULT_NAMES: string[] = [
  EToolName.WriteFile,
  EToolName.FileReader,
  'query_prometheus',
  'get_dashboard_panel_queries',
];

export const ReusableTools: string[] = [
  EToolName.GetGeolocation,
  EToolName.GetWeather,
  EToolName.GetTrainRoute,
  EToolName.SearchPoiByLocation,
  EToolName.SearchPoiByName,
  EToolName.SearchPoiByType,
  EToolName.VideoReader,
  EToolName.ImageReader,
  EToolName.TextToImage,
];

export const InternalTools: string[] = [EToolName.Planning, EToolName.Next, EToolName.Deliver];

export enum ETaskStatus {
  Successful = 'successful',
  InformationRequired = 'information-required',
  Failed = 'failed',
}

export const TaskStatusText = {
  [ETaskStatus.Successful]: '成功',
  [ETaskStatus.InformationRequired]: '需要补充信息',
  [ETaskStatus.Failed]: '失败',
};

