import axios from 'axios';
import { Conversation, ChatEvent, ResumePayload } from '@/types';
import { API_BASE_URL, EVENT_ERROR } from './const';

export const api = axios.create({
  baseURL: API_BASE_URL,
});

export const unwrapApiEnvelope = <T>(response: { data: T }): T => response.data;

export const getConversations = async () => {
  const response = await api.get<{ data: Conversation[] }>('/conversations');
  return unwrapApiEnvelope(response.data);
};

export const getModels = async () => {
  const response = await api.get<{
    data: {
      models: string[];
      modelContextWindows: Record<string, number>;
    };
  }>('/models');
  return unwrapApiEnvelope(response.data);
};

export const deleteConversation = async (id: string) => {
  return api.delete(`/conversation/${id}`);
};

export const stopConversation = async (id: string) => {
  return api.post(`/conversation/${id}/stop`);
};

export const getConversationStatus = async (id: string) => {
  const response = await api.get<{
    data: {
      model: string;
      generating: boolean;
      tokenUsage?: {
        inputTokens: number;
        outputTokens: number;
        totalTokens: number;
        promptTokens?: number;
        completionTokens?: number;
        cachedInputTokens?: number;
        reasoningOutputTokens?: number;
      };
    };
  }>(`/conversation/${id}`);
  return unwrapApiEnvelope(response.data);
};

export const getSessionFiles = async (id: string) => {
  const response = await api.get<{ data: string[] }>(`/chat/session-files/${id}`);
  return unwrapApiEnvelope(response.data);
};

export const getSkills = async () => {
  const response = await api.get<{ data: string[] }>('/chat/skills');
  return unwrapApiEnvelope(response.data);
};

export const getSessionFileContent = async (id: string, filePath: string) => {
  const response = await api.get<{ data: string }>(`/chat/session-files/${id}/content`, {
    params: { path: filePath },
  });
  return unwrapApiEnvelope(response.data);
};

const parseStreamChunk = (buffer: string, onChunk: (event: ChatEvent) => void) => {
  const lines = buffer.split('\n');
  let remaining = lines.pop() || '';

  for (const line of lines) {
      const trimmed = line.trim();
      if (trimmed) {
          try {
              const rawEvent = JSON.parse(trimmed) as Partial<ChatEvent> & Record<string, unknown>;
              const event: ChatEvent = {
                  event: (rawEvent.event as ChatEvent['event']) || EVENT_ERROR,
                  data: rawEvent.data,
                  node: typeof rawEvent.node === 'string' ? rawEvent.node : undefined,
                  timestamp: typeof rawEvent.timestamp === 'number' ? rawEvent.timestamp : undefined,
                  subagentType: typeof rawEvent.subagent_type === 'string' ? rawEvent.subagent_type : undefined,
                  subagentNamespace: typeof rawEvent.subagent_namespace === 'string' ? rawEvent.subagent_namespace : undefined,
                  source:
                    rawEvent.source && typeof rawEvent.source === 'object'
                      ? rawEvent.source as ChatEvent['source']
                      : undefined,
              };
              onChunk(event);
          } catch (e) {
              const isPartial = trimmed.startsWith('{') && !trimmed.endsWith('}');
              if (isPartial) {
                  remaining = `${trimmed}\n${remaining}`;
              } else {
                  onChunk({
                      event: EVENT_ERROR,
                      data: { message: 'JSON parse error', raw: trimmed },
                  });
              }
          }
      }
  }
  return remaining;
};

export const sendMessage = async (
  data: { model: string; text?: string; id?: string; resume?: ResumePayload },
  onChunk: (event: ChatEvent) => void,
  signal?: AbortSignal
) => {
  let buffer = '';
  let receivedLength = 0;

  await api.post('/chat', data, {
      signal,
      onDownloadProgress: (progressEvent) => {
          const xhr = progressEvent.event?.target as XMLHttpRequest | null;
